function UIItemList:InitUIListByType(uiType,root)
    local uiList
    local listType = uiType or UIItemList.NORMAL
    if listType == UIItemList.NORMAL then
        uiList = UIListEasy:New()
    elseif listType == UIItemList.WRAP then
        uiList = UIListWrap:New()
    elseif listType == UIItemList.CIRCLE then
        uiList = UIListCircle:New()
    elseif listType == UIItemList.SUPER then
        uiList = UISuperList:New()
    elseif listType == UIItemList.SUPER_GRID then
        uiList = UISuperList:New()
        uiList:SetScrollType(2)
    else
        LogError("wrong type"..uiType)
        return
    end
    self._listType = listType
    uiList:Create(self._parentWnd,root)
    return uiList
end

function UIItemList:Create(root,dataList,setFunc,uiType,bRefresh,bMult)
    if(bRefresh == nil)then
        bRefresh = true
    end

    self:Clear()

    self._uiItemList = {}

    local uiList = self._uiList
    if not uiList then
        uiList = self:InitUIListByType(uiType,root)
        self._uiList = uiList
    end

    if uiList then
        uiList:SetFuncOnItemDraw(setFunc)
    end

    uiList:RemoveAll()
	local cnt = 0
	if dataList then
		cnt = #dataList
		for i=1,cnt do
			uiList:AddData(i,dataList[i])
		end	
	end
    
	if bMult == nil and cnt > 10 then
		bMult = true
	end
	if nil ~= bMult then
		uiList:SetMultScroll(bMult)
	end



    if not bRefresh then
        if uiType == UIItemList.SUPER or uiType == UIItemList.SUPER_GRID then
            uiList:RefreshList() ---superlist 必须调用，需要初始化
        end
        return
    end

    uiList:RefreshList()
end

