function UIItemList:InitListData(data)

    local root = data.root
    local dataList = data.dataList
    local setFunc = data.setFunc
    local uiType = data.type or UIItemList.NORMAL
    local onCenterFunc = data.onCenterFunc
    local centerPos = data.centerPos
    local speed = data.speed
    local onReturnFunc = data.onReturnFunc
    local notRefresh = data.notRefresh
    local metaData = data.metaData

    self:Clear()

    self._uiItemList = {}

    local uiList = self._uiList
    if not uiList then
        uiList = self:InitUIListByType(uiType,root)
        self._uiList = uiList
    end

    if not uiList then
        return
    end

    uiList:SetMetaData(metaData)
    if setFunc then
        uiList:SetFuncOnItemDraw(setFunc)
    end

    if onCenterFunc and uiList.SetFuncOnItemCenter then
        uiList:SetFuncOnItemCenter(onCenterFunc)
    end

    if onReturnFunc and uiList.SetFuncOnItemReturn then
        uiList:SetFuncOnItemReturn(onReturnFunc)
    end


    uiList:RemoveAll()
    local cnt = #dataList
    for i=1,cnt do
        uiList:AddData(i,dataList[i])
    end



    if notRefresh then
        if uiType == UIItemList.SUPER or uiType == UIItemList.SUPER_GRID then
            uiList:RefreshList() ---superlist 必须调用，需要初始化
        end
        return
    end

    if uiType == UIItemList.CIRCLE then
        uiList:RefreshList(centerPos,speed)
    else
        uiList:RefreshList()
    end
end

