function UIItemList:RefreshData(dataList,isNotRefresh)
    local list = self._uiList
    if not list then
        return
    end
    list:RemoveAllData()
    for k,v in ipairs(dataList) do
        list:AddData(k,v)
    end
    if(not isNotRefresh)then

        if self._listType == UIItemList.SUPER or self._listType == UIItemList.SUPER_GRID then
            list:RefreshList()
        else
            list:DrawAllItems()
        end
    end
end

function UIItemList:RefreshList(dataList, isNotRefresh, isReset)
    local uiList = self._uiList
    if not uiList then
        return
    end
    uiList:RemoveAll()
    local cnt = #dataList
    for i=1,cnt do
        uiList:AddData(i,dataList[i])
    end
    local listType = self._listType
    if(not isNotRefresh)then
		if listType == UIItemList.NORMAL then
			uiList:RefreshList(isReset)
		elseif listType == UIItemList.WRAP then
			uiList:RefreshList(nil,nil,nil,isReset)
		elseif listType == UIItemList.CIRCLE then
			uiList:RefreshList(nil,nil,isReset)
		elseif listType == UIItemList.SUPER then
			uiList:RefreshList(isReset)
		elseif listType == UIItemList.SUPER_GRID then
			uiList:RefreshList(isReset)
		else
			uiList:RefreshList()
		end 
    end
end
function UIItemList:ResetList(dataList, isNotRefresh)
    local uiList = self._uiList
    if not uiList then
        return
    end
    uiList:RemoveAll()
    local cnt = #dataList
    for i=1,cnt do
        uiList:AddData(i,dataList[i])
    end
    if(not isNotRefresh)then
		uiList:ResetList()
    end
end

function UIItemList:RefreshSimpleList(dataList)--UIListWrap才有
    local uiList = self._uiList
    if not uiList then
        return
    end
    uiList:RemoveAll()
    local cnt = #dataList
    for i=1,cnt do
        uiList:AddData(i,dataList[i])
    end
    uiList:RefreshSimpleList()
end

function UIItemList:RefreshOnlyData(dataList)
    local list = self._uiList
    if not list then
        return
    end
    list:RemoveAllData()
    for k,v in ipairs(dataList) do
        list:AddData(k,v)
    end
end

function UIItemList:DrawAllItems(bLoadAni)
    local list = self._uiList
    if not list then
        return
    end
    list:DrawAllItems(bLoadAni)
end

function UIItemList:EnableLoadAnimation(bEnable, aniTime, onceCount, aniType)
    local uiList = self._uiList
    if uiList then
        uiList:EnableLoadAnimation(bEnable, aniTime, onceCount, aniType)
    end
end

function UIItemList:MoveToPos(index,offset, offsetY)
    if not self._uiList then
        return
    end
    if self._listType == UIItemList.SUPER or self._listType == UIItemList.SUPER_GRID then
        self._uiList:MoveToPos(index,offset, nil, offsetY)
    elseif self._listType == UIItemList.NORMAL then
        self._uiList:DelayScrollTo(index,UIListEasy.SCROLL_TOP)
    end

end
