------------------------------------------------------------------
function UIItemList:Destroy()
    if self._isDestroy then return end
    self:Clear()
    if self._uiList then
        self._uiList:OnWndClose()
        self._uiList = nil
    end
    table.removeall(self)
    self._isDestroy = true
end

function UIItemList:Clear()
    if self._uiItemList then
        for k,v in pairs(self._uiItemList) do
            if v.Destroy then
                v:Destroy()
            end
        end
    end
    self._uiItemList = nil
end

function UIItemList:OnWndClose()
    self:Destroy()
end

function UIItemList:Freeze(bFrozen)
    if not self._uiList then return end
    local isSuper= self._listType == UIItemList.SUPER or self._listType == UIItemList.SUPER_GRID
    if not isSuper then return end
    self._uiList:Freeze(bFrozen)
end
